const query = $json.query ?? {};
const body = $json.body ?? {};
const params = $json.params ?? {};

function pick(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return undefined;
}

function asNumber(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

const adId = String(pick(params.adId, query.ad_id, body.ad_id, 'mock_ad_001')).trim();
const scenario = String(pick(query.scenario, body.scenario, 'success')).trim().toLowerCase();

const forcedStatus = asNumber(pick(query.statusCode, query.status_code, body.statusCode, body.status_code));

let statusCode = 200;
if (forcedStatus !== null) {
  statusCode = forcedStatus;
} else if (scenario === 'retry429') {
  statusCode = 429;
} else if (scenario === 'retry500') {
  statusCode = 500;
} else if (scenario === 'fail400') {
  statusCode = 400;
}

let effectiveStatus = String(pick(query.effective_status, body.effective_status, 'ACTIVE')).trim().toUpperCase();
if (scenario === 'inactive') effectiveStatus = 'PAUSED';

let name = String(pick(query.name, body.name, 'Black Friday Teaser')).trim();
if (scenario === 'name_mismatch') name = `UNMATCHED_${adId}`;

const successBody = {
  id: adId,
  name,
  effective_status: effectiveStatus
};

const errorBody = {
  error: {
    message: `Mock Meta precheck scenario=${scenario}`,
    code: statusCode
  },
  ...successBody
};

return [{
  json: {
    statusCode,
    body: statusCode >= 200 && statusCode < 300 ? successBody : errorBody,
    scenario
  }
}];

